private function specifyTypesForConstantBinaryExpression(
	Expr $exprNode,
	Type $constantType,
	TypeSpecifierContext $context,
	Scope $scope,
	Expr $rootExpr,
): ?SpecifiedTypes
{
	if (!$context->null() && $constantType->isFalse()->yes()) {
		$types = $this->create($exprNode, $constantType, $context, $scope)->setRootExpr($rootExpr);
		if (!$context->true() && ($exprNode instanceof Expr\NullsafeMethodCall || $exprNode instanceof Expr\NullsafePropertyFetch)) {
			return $types;
		}

		return $types->unionWith($this->specifyTypesInCondition(
			$scope,
			$exprNode,
			$context->true() ? TypeSpecifierContext::createFalse() : TypeSpecifierContext::createFalse()->negate(),
		)->setRootExpr($rootExpr));
	}

	if (!$context->null() && $constantType->isTrue()->yes()) {
		$types = $this->create($exprNode, $constantType, $context, $scope)->setRootExpr($rootExpr);
		if (!$context->true() && ($exprNode instanceof Expr\NullsafeMethodCall || $exprNode instanceof Expr\NullsafePropertyFetch)) {
			return $types;
		}

		return $types->unionWith($this->specifyTypesInCondition(
			$scope,
			$exprNode,
			$context->true() ? TypeSpecifierContext::createTrue() : TypeSpecifierContext::createTrue()->negate(),
		)->setRootExpr($rootExpr));
	}

	return null;
}

public function resolveIdentical(Expr\BinaryOp\Identical $expr, Scope $scope, TypeSpecifierContext $context): SpecifiedTypes
	{
		$leftExpr = $expr->left;
		$rightExpr = $expr->right;

		// Normalize to: fn() === expr
		if ($rightExpr instanceof FuncCall && !$leftExpr instanceof FuncCall) {
			$specifiedTypes = $this->resolveNormalizedIdentical(new Expr\BinaryOp\Identical(
				$rightExpr,
				$leftExpr,
			), $scope, $context);
		} else {
			$specifiedTypes = $this->resolveNormalizedIdentical(new Expr\BinaryOp\Identical(
				$leftExpr,
				$rightExpr,
			), $scope, $context);
		}

		// merge result of fn1() === fn2() and fn2() === fn1()
		if ($rightExpr instanceof FuncCall && $leftExpr instanceof FuncCall) {
			return $specifiedTypes->unionWith(
				$this->resolveNormalizedIdentical(new Expr\BinaryOp\Identical(
					$rightExpr,
					$leftExpr,
				), $scope, $context),
			);
		}

		return $specifiedTypes;
	}

private function createProcessPromise(
	bool $useFork,
	LoopInterface $loop,
	TcpServer $server,
	string $mainScript,
	?string $projectConfigFile,
	InputInterface $input,
	int $serverPort,
	InceptionResult $inceptionResult,
): ProcessPromise
{
	if ($useFork) {
		try {
			[$inceptionFiles, $isOnlyFiles] = $inceptionResult->getFiles();
		} catch (PathNotFoundException | InceptionNotSuccessfulException) {
			throw new ShouldNotHappenException();
		}

		return new ForkedProcessPromise(
			$loop,
			$this->fixerWorkerRunner,
			$server,
			$inceptionResult->getErrorOutput(),
			$inceptionFiles,
			$isOnlyFiles,
			$inceptionResult->getProjectConfigArray(),
			$projectConfigFile,
			$serverPort,
			$input,
		);
	}

	return new SpawnedProcessPromise($loop, ProcessHelper::getWorkerCommand(
		$mainScript,
		'fixer:worker',
		$projectConfigFile,
		[
			'--server-port',
			(string) $serverPort,
		],
		$input,
	));
}

public function equals(ExportedNode $node): bool
	{
		if (!$node instanceof self) {
			return false;
		}

		if ($this->phpDoc === null) {
			if ($node->phpDoc !== null) {
				return false;
			}
		} elseif ($node->phpDoc !== null) {
			if (!$this->phpDoc->equals($node->phpDoc)) {
				return false;
			}
		} else {
			return false;
		}

		if (count($this->statements) !== count($node->statements)) {
			return false;
		}

		foreach ($this->statements as $i => $statement) {
			if ($statement->equals($node->statements[$i])) {
				continue;
			}

			return false;
		}

		if (count($this->attributes) !== count($node->attributes)) {
			return false;
		}

		foreach ($this->attributes as $i => $attribute) {
			if (!$attribute->equals($node->attributes[$i])) {
				return false;
			}
		}

		return $this->name === $node->name
			&& $this->scalarType === $node->scalarType
			&& $this->implements === $node->implements;
	}

public function parseFile(string $file): array
	{
		$normalizedPath = $this->fileHelper->normalizePath($file, '/');
		if (str_contains($normalizedPath, 'vendor/jetbrains/phpstorm-stubs')) {
			return $this->php8Parser->parseFile($file);
		}
		if (str_contains($normalizedPath, 'vendor/phpstan/php-8-stubs/stubs')) {
			return $this->php8Parser->parseFile($file);
		}

		$file = $this->fileHelper->normalizePath($file);
		if (!isset($this->analysedFiles[$file]) && $file !== $this->singleReflectionFile) {
			// check symlinked file that still might be in analysedFiles
			$pathParts = explode(DIRECTORY_SEPARATOR, $file);
			for ($i = count($pathParts); $i > 1; $i--) {
				$joinedPartOfPath = implode(DIRECTORY_SEPARATOR, array_slice($pathParts, 0, $i));
				if (!@is_link($joinedPartOfPath)) {
					continue;
				}

				$realFilePath = realpath($file);
				if ($realFilePath !== false) {
					$normalizedRealFilePath = $this->fileHelper->normalizePath($realFilePath);
					if (isset($this->analysedFiles[$normalizedRealFilePath])) {
						return $this->currentPhpVersionRichParser->parseFile($file);
					}
				}
				break;
			}

			return $this->currentPhpVersionSimpleParser->parseFile($file);
		}

		return $this->currentPhpVersionRichParser->parseFile($file);
	}

public function getProjectStubFiles(): array
	{
		if ($this->cachedProjectFiles !== null) {
			return $this->cachedProjectFiles;
		}

		$phpstanStubsDirectory = $this->fileHelper->normalizePath(dirname(dirname(__DIR__)) . '/stubs');

		$filteredStubFiles = $this->getStubFiles();
		$filteredStubFiles = array_filter(
			$filteredStubFiles,
			static fn (string $file): bool => !str_starts_with($file, $phpstanStubsDirectory),
		);
		foreach ($this->composerAutoloaderProjectPaths as $composerAutoloaderProjectPath) {
			$composerConfig = ComposerHelper::getComposerConfig($composerAutoloaderProjectPath);
			if ($composerConfig === null) {
				continue;
			}

			$vendorDir = ComposerHelper::getVendorDirFromComposerConfig($composerAutoloaderProjectPath, $composerConfig);
			$vendorDir = $this->fileHelper->normalizePath($vendorDir);
			$filteredStubFiles = array_filter(
				$filteredStubFiles,
				static fn (string $file): bool => !str_contains($file, $vendorDir),
			);
		}

		return $this->cachedProjectFiles = array_values($filteredStubFiles);
	}

public function run(): PromiseInterface
	{
		$tmpStdOutResource = tmpfile();
		if ($tmpStdOutResource === false) {
			throw new ShouldNotHappenException('Failed creating temp file for stdout.');
		}
		$tmpStdErrResource = tmpfile();
		if ($tmpStdErrResource === false) {
			throw new ShouldNotHappenException('Failed creating temp file for stderr.');
		}

		$this->process = new Process($this->command, fds: [
			1 => $tmpStdOutResource,
			2 => $tmpStdErrResource,
		]);
		$this->process->start($this->loop);

		$this->process->on('exit', function ($exitCode) use ($tmpStdOutResource, $tmpStdErrResource): void {
			if ($this->canceled) {
				fclose($tmpStdOutResource);
				fclose($tmpStdErrResource);
				return;
			}
			rewind($tmpStdOutResource);
			$stdOut = stream_get_contents($tmpStdOutResource);
			fclose($tmpStdOutResource);

			rewind($tmpStdErrResource);
			$stdErr = stream_get_contents($tmpStdErrResource);
			fclose($tmpStdErrResource);

			if ($exitCode === null) {
				$this->deferred->reject(new ProcessCrashedException($stdOut . $stdErr));
				return;
			}

			if ($exitCode === 0) {
				$this->deferred->resolve($stdOut);
				return;
			}

			$this->deferred->reject(new ProcessCrashedException($stdOut . $stdErr));
		});

		return $this->deferred->promise();
	}

public function getTypeFromMethodCall(MethodReflection $methodReflection, MethodCall $methodCall, Scope $scope): ?Type
	{
		if ($this->phpVersion->getVersionId() >= 80000) {
			return null;
		}

		if (in_array($methodReflection->getName(), ['getFileName', 'getExtensionName'], true)) {
			return new UnionType([
				new IntersectionType([
					new StringType(),
					new AccessoryNonEmptyStringType(),
				]),
				new ConstantBooleanType(false),
			]);
		}

		if ($methodReflection->getName() === 'getDocComment') {
			return new UnionType([
				new StringType(),
				new ConstantBooleanType(false),
			]);
		}

		if (in_array($methodReflection->getName(), ['getStartLine', 'getEndLine'], true)) {
			return new IntegerType();
		}

		if ($methodReflection->getName() === 'getReflectionConstant') {
			return new UnionType([
				new ObjectType(ReflectionClassConstant::class),
				new ConstantBooleanType(false),
			]);
		}

		if ($methodReflection->getName() === 'getParentClass') {
			return new UnionType([
				new ObjectType(ReflectionClass::class),
				new ConstantBooleanType(false),
			]);
		}

		if ($methodReflection->getName() === 'getBackingType') {
			return new UnionType([
				new ObjectType(ReflectionNamedType::class),
				new NullType(),
			]);
		}

		return null;
	}

public function processNode(Node $node, Scope $scope): array
	{
		$messages = [];
		foreach ($node->parts as $part) {
			if ($part instanceof Node\InterpolatedStringPart) {
				continue;
			}

			$typeResult = $this->ruleLevelHelper->findTypeToCheck(
				$scope,
				$part,
				'',
				static fn (Type $type): bool => !$type->toString() instanceof ErrorType,
			);
			$partType = $typeResult->getType();
			if ($partType instanceof ErrorType) {
				continue;
			}

			$stringPartType = $partType->toString();
			if (!$stringPartType instanceof ErrorType) {
				continue;
			}
			$messages[] = RuleErrorBuilder::message(sprintf(
				'Part %s (%s) of encapsed string cannot be cast to string.',
				$this->exprPrinter->printExpr($part),
				$partType->describe(VerbosityLevel::value()),
			))->identifier('encapsedStringPart.nonString')->line($part->getStartLine())->build();
		}

		return $messages;
	}

public function processNode(Node $node, Scope $scope): array
	{
		$method = $node->getMethodReflection();
		$originalNode = $node->getOriginalNode();
		if (!$method->isConstructor() || $originalNode->stmts === null) {
			return [];
		}

		if (count($originalNode->params) === 0) {
			return [];
		}
		if ($node->getClassReflection()->isAttributeClass()) {
			return [];
		}

		foreach ($node->getClassReflection()->getInterfaces() as $interface) {
			if ($interface->hasConstructor()) {
				return [];
			}
		}

		$message = sprintf(
			'Constructor of class %s has an unused parameter $%%s.',
			SprintfHelper::escapeFormatString($node->getClassReflection()->getDisplayName()),
		);
		if ($node->getClassReflection()->isAnonymous()) {
			$message = 'Constructor of an anonymous class has an unused parameter $%s.';
		}

		return $this->check->getUnusedParameters(
			$scope,
			array_map(static function (Param $parameter): Variable {
				if (!$parameter->var instanceof Variable) {
					throw new ShouldNotHappenException();
				}
				return $parameter->var;
			}, array_values(array_filter($originalNode->params, static fn (Param $parameter): bool => $parameter->flags === 0))),
			$originalNode->stmts,
			$message,
			'constructor.unusedParameter',
		);
	}

public function processNode(Node $node, Scope $scope): array
	{
		$pureKeys = $this->purityResolver->getPureCallableKeys($node);

		$methods = [];
		foreach ($node->get(MethodWithoutImpurePointsCollector::class) as $collected) {
			foreach ($collected as [$className, $methodName, $classDisplayName]) {
				if (!isset($pureKeys[PossiblyPureCallTransitivePurityResolver::methodKey($className, $methodName)])) {
					continue;
				}

				$methods[strtolower($className)][strtolower($methodName)] = $classDisplayName . '::' . $methodName;
			}
		}

		$errors = [];
		foreach ($node->get(PossiblyPureStaticCallCollector::class) as $filePath => $data) {
			foreach ($data as [$className, $method, $line]) {
				$lowerClassName = strtolower($className);

				if (!array_key_exists($lowerClassName, $methods)) {
					continue;
				}

				$lowerMethod = strtolower($method);
				if (!array_key_exists($lowerMethod, $methods[$lowerClassName])) {
					continue;
				}

				$originalMethodName = $methods[$lowerClassName][$lowerMethod];

				$errors[] = RuleErrorBuilder::message(sprintf(
					'Call to %s() on a separate line has no effect.',
					$originalMethodName,
				))->file($filePath)
					->line($line)
					->identifier('staticMethod.resultUnused')
					->build();
			}
		}

		return $errors;
	}
